@app.route('/get_tagged_solutions', methods=['POST'])
def get_tagged_solutions():
    tag = request.form['tag']

    query = "SELECT solution_id FROM tags WHERE tag = ?"
    db = get_db()
    cursor = db.cursor()
    cursor.execute(query, [tag])
    solution_ids = [solution_id for solution_id, in cursor.fetchall()]

    if solution_ids:
        query = f"SELECT * FROM solutions WHERE id IN ({','.join('?' * len(solution_ids))})"
        cursor.execute(query, solution_ids)
        solutions = cursor.fetchall()
    else:
        solutions = []

    return jsonify(solutions)

